/**
 * Parses the 'if'/'then'/'else' conditional keywords.
 *
 * - the 'if' schema is evaluated silently (a failure to match is not itself an error)
 * - if the data matches 'if', it must also match 'then' (when present)
 * - if the data does not match 'if', it must match 'else' (when present)
 * - 'then'/'else' without 'if' are no-ops and ignored by the caller
 */
export const parseConditionalJsonSchema = (
	jsonSchema: JsonSchema
): Type | undefined => {
	if (!("if" in jsonSchema)) return

	const ifValidator = jsonSchemaToType(jsonSchema.if)
	const thenValidator =
		"then" in jsonSchema ? jsonSchemaToType(jsonSchema.then) : undefined
	const elseValidator =
		"else" in jsonSchema ? jsonSchemaToType(jsonSchema.else) : undefined

	// 'if' with no 'then'/'else' imposes no constraints, but is still a valid schema.
	if (thenValidator === undefined && elseValidator === undefined)
		return type.unknown

	const jsonSchemaConditionalValidator = (data: unknown, ctx: Traversal) => {
		if (ifValidator.allows(data)) {
			if (thenValidator !== undefined && !thenValidator.allows(data)) {
				return ctx.reject({
					expected: `${thenValidator.description} (since it matches the 'if' schema '${ifValidator.description}')`,
					actual: printable(data)
				})
			}
		} else if (elseValidator !== undefined && !elseValidator.allows(data)) {
			return ctx.reject({
				expected: `${elseValidator.description} (since it does not match the 'if' schema '${ifValidator.description}')`,
				actual: printable(data)
			})
		}
		return true
	}

	return type.unknown.narrow(jsonSchemaConditionalValidator)
}
