import { printable } from "@ark/util"
import { type, type JsonSchema, type Type } from "arktype"
import { jsonSchemaToType } from "./json.ts"

const isObject = (data: unknown): data is object =>
	typeof data === "object" && data !== null && !Array.isArray(data)

/**
 * Parses the 'dependentRequired', 'dependentSchemas' and (draft-07) 'dependencies'
 * keywords:
 *
 * - dependentRequired: if a trigger key is present, its dependent keys must also be present
 * - dependentSchemas: if a trigger key is present, the object must match the dependent schema
 * - dependencies: the draft-07 combination of the above (array value => dependentRequired,
 *   schema value => dependentSchemas)
 *
 * All three only constrain objects; non-objects are unaffected.
 */
export const parseDependenciesJsonSchema = (
	jsonSchema: JsonSchema
): Type | undefined => {
	const requiredDependencies: [key: string, dependentKeys: readonly string[]][] =
		[]
	const schemaDependencies: [key: string, validator: Type][] = []

	const collectDependency = (key: string, value: unknown) => {
		if (Array.isArray(value))
			requiredDependencies.push([key, value as readonly string[]])
		else
			schemaDependencies.push([key, jsonSchemaToType(value as JsonSchema.Branch)])
	}

	if ("dependentRequired" in jsonSchema) {
		for (const key in jsonSchema.dependentRequired)
			requiredDependencies.push([key, jsonSchema.dependentRequired[key]])
	}
	if ("dependentSchemas" in jsonSchema) {
		for (const key in jsonSchema.dependentSchemas)
			schemaDependencies.push([
				key,
				jsonSchemaToType(jsonSchema.dependentSchemas[key])
			])
	}
	if ("dependencies" in jsonSchema) {
		for (const key in jsonSchema.dependencies)
			collectDependency(key, jsonSchema.dependencies[key])
	}

	if (requiredDependencies.length === 0 && schemaDependencies.length === 0)
		return

	const jsonSchemaDependenciesValidator = (data: unknown, ctx: Traversal) => {
		if (!isObject(data)) return true

		for (const [key, dependentKeys] of requiredDependencies) {
			if (!(key in data)) continue
			for (const dependentKey of dependentKeys) {
				if (!(dependentKey in data)) {
					ctx.reject({
						expected: `a value for '${dependentKey}' (required when '${key}' is present)`,
						actual: `missing`
					})
				}
			}
		}

		for (const [key, validator] of schemaDependencies) {
			if (!(key in data)) continue
			if (!validator.allows(data)) {
				ctx.reject({
					expected: `${validator.description} (required when '${key}' is present)`,
					actual: printable(data)
				})
			}
		}

		return !ctx.hasError()
	}

	return type.unknown.narrow(jsonSchemaDependenciesValidator)
}
