/** structural (deep) equality for JSON values */
const jsonDeepEquals = (l: unknown, r: unknown): boolean => {
	if (l === r) return true
	if (typeof l !== "object" || typeof r !== "object" || l === null || r === null)
		return false

	if (Array.isArray(l) || Array.isArray(r)) {
		if (!Array.isArray(l) || !Array.isArray(r) || l.length !== r.length)
			return false
		return l.every((item, i) => jsonDeepEquals(item, r[i]))
	}

	const lKeys = Object.keys(l)
	const rKeys = Object.keys(r as object)
	if (lKeys.length !== rKeys.length) return false
	return lKeys.every(
		key =>
			key in (r as object) &&
			jsonDeepEquals(
				(l as Record<string, unknown>)[key],
				(r as Record<string, unknown>)[key]
			)
	)
}

const hasNonPrimitiveValue = (values: readonly unknown[]): boolean =>
	values.some(value => typeof value === "object" && value !== null)

// JSON Schema 'const'/'enum' use structural equality, whereas ArkType's
// 'unit'/'enumerated' use reference (===) equality. For object/array values we
// therefore fall back to a deep-equality narrow.
const deepEqualsOneOf = (values: readonly unknown[]): Type => {
	const jsonSchemaEnumValidator = (data: unknown, ctx: Traversal) =>
		values.some(value => jsonDeepEquals(data, value)) ?
			true
		:	ctx.reject({
				expected: `one of ${printable(values)}`,
				actual: printable(data)
			})

	return type.unknown.narrow(jsonSchemaEnumValidator) as Type
}

export const parseCommonJsonSchema = (
	jsonSchema: JsonSchema
): Type | undefined => {
	if ("const" in jsonSchema) {
		if ("enum" in jsonSchema)
			throwParseError(writeJsonSchemaCommonConstAndEnumMessage())

		return (
			typeof jsonSchema.const === "object" && jsonSchema.const !== null ?
				deepEqualsOneOf([jsonSchema.const])
			:	type.unit(jsonSchema.const)
		)
	}

	if ("enum" in jsonSchema) {
		return (
			hasNonPrimitiveValue(jsonSchema.enum) ?
				deepEqualsOneOf(jsonSchema.enum)
			:	type.enumerated(...jsonSchema.enum)
		)
	}
}
