import { printable, throwParseError } from "@ark/util"
import { type, type JsonSchema, type Type } from "arktype"
import {
	writeJsonSchemaUnresolvableRefMessage,
	writeJsonSchemaUnsupportedRefMessage
} from "./errors.ts"
import { jsonSchemaToType } from "./json.ts"

const refPrefix = "#/$defs/"

interface RefContext {
	defs: Record<string, JsonSchema.Branch>
	built: Record<string, Type>
}

// A stack is used (rather than a single value) so that nested schemas which
// declare their own '$defs' shadow rather than clobber an enclosing scope.
const refContextStack: RefContext[] = []

const currentRefContext = (): RefContext | undefined =>
	refContextStack.at(-1)

const parseLocalRefName = (ref: string): string => {
	if (!ref.startsWith(refPrefix))
		return throwParseError(writeJsonSchemaUnsupportedRefMessage())

	const name = ref.slice(refPrefix.length)
	// only a single, non-empty path segment (i.e. a direct key of '$defs') is
	// supported - nested JSON pointers such as "#/$defs/Foo/properties/bar" are not
	if (name === "" || name.includes("/"))
		return throwParseError(writeJsonSchemaUnsupportedRefMessage())

	return name
}

export const parseJsonSchemaRef = (ref: string): Type => {
	const name = parseLocalRefName(ref)
	const ctx = currentRefContext()

	if (ctx === undefined || !(name in ctx.defs))
		return throwParseError(writeJsonSchemaUnresolvableRefMessage(ref))

	// If the referenced definition has already been parsed, embed it directly so
	// that its structure (and thus error messages/introspection) is preserved.
	const alreadyBuilt = ctx.built[name]
	if (alreadyBuilt !== undefined) return alreadyBuilt

	// Otherwise this is a self- or forward-reference (e.g. a recursive $def).
	// Resolve it lazily at validation time so that parsing terminates instead of
	// infinitely expanding the recursive definition.
	const jsonSchemaRefValidator = (data: unknown, traversal: Traversal) => {
		const resolved = ctx.built[name]
		if (resolved === undefined)
			return throwParseError(writeJsonSchemaUnresolvableRefMessage(ref))

		return resolved.allows(data) ?
				true
			:	traversal.reject({
					expected: `a value matching $ref ${ref}`,
					actual: printable(data)
				})
	}
	return type.unknown.narrow(jsonSchemaRefValidator) as Type
}

/**
 * Registers a schema's local '$defs' (if any) as resolvable '$ref' targets while
 * `parse` runs, then restores the previous ref scope. Recursive and mutually
 * recursive definitions are supported.
 */
export const parseJsonSchemaWithDefs = (
	jsonSchema: JsonSchema,
	parse: () => Type
): Type => {
	const defs = (jsonSchema as { $defs?: Record<string, JsonSchema.Branch> })
		.$defs

	if (defs === undefined) return parse()

	const ctx: RefContext = { defs, built: {} }
	refContextStack.push(ctx)
	try {
		// Eagerly parse every definition so that non-recursive '$ref's can be
		// embedded directly. Recursive references encountered while a definition
		// is still being built fall back to lazy resolution (see parseJsonSchemaRef).
		for (const name in defs) ctx.built[name] = jsonSchemaToType(defs[name])
		return parse()
	} finally {
		refContextStack.pop()
	}
}
